external_knowledge:
- "golden treasures" refers to the products sold;
- "bringing in the most gold" refers to generating the highest revenue;
- "shining units" refers to the units sold;
- "treasure hunters" refers to the customers making the purchases;
- "overall satisfaction" refers to the rating given by the customers.

sql:
SELECT COUNT(DISTINCT product_id) AS unique_products_sold
FROM sales
WHERE rating > 4;

SELECT AVG(gross_income) AS average_gross_income
FROM sales
WHERE sale_date BETWEEN '2023-05-01' AND '2023-05-31';
